using System.ComponentModel;
using DevExpress.XtraReports.Parameters;

int groupCounter = 1;

private void GroupFooter1_BeforePrint(object sender, CancelEventArgs e)
{
    GroupFooterBand groupFooter = (GroupFooterBand)sender;
    XtraReport report = (XtraReport)groupFooter.Report;

    Parameter noOfGroupsPerPageParam = report.Parameters["NoOfGroupsPerPage"];
    if(noOfGroupsPerPageParam != null && noOfGroupsPerPageParam.Value != "")
    {
        int noOfGroupsPerPage = Convert.ToInt32(noOfGroupsPerPageParam.Value);
        if (noOfGroupsPerPage > 0)
        {
            if (groupCounter == noOfGroupsPerPage)
            {
                groupFooter.PageBreak = PageBreak.AfterBand;
                groupCounter = 1;
            }
            else
            {
                groupFooter.PageBreak = PageBreak.None;
                groupCounter += 1;
            }
        }
    }
}
